1	import { describe, it, expect } from "vitest";
2	import { render, screen } from "@testing-library/react";
3	import { AnalyticsSummaryCards } from "@/features/analytics/AnalyticsSummaryCards";
4	import { formatCurrency } from "@/lib/utils/format";
5	import type { MarketAnalyticsSummary } from "@/lib/api/types";
6	
7	const makeSummary = (overrides: Partial<MarketAnalyticsSummary> = {}): MarketAnalyticsSummary => ({
8	  totalTrades: 1234,
9	  totalVolume: 56789.42,
10	  uniqueTraders: 312,
11	  bucketInterval: "day",
12	  lastUpdated: "2025-03-15T10:30:00Z",
13	  ...overrides,
14	});
15	
16	describe("AnalyticsSummaryCards", () => {
17	  it("renders all four card labels", () => {
18	    render(<AnalyticsSummaryCards summary={makeSummary()} />);
19	    expect(screen.getByText("Total Activity")).toBeInTheDocument();
20	    expect(screen.getByText("Total Volume")).toBeInTheDocument();
21	    expect(screen.getByText("Unique Traders")).toBeInTheDocument();
22	    expect(screen.getByText("Last Update")).toBeInTheDocument();
23	  });
24	
25	  it("renders correctly formatted values", () => {
26	    const summary = makeSummary();
27	    render(<AnalyticsSummaryCards summary={summary} />);
28	
29	    expect(screen.getByText(summary.totalTrades.toLocaleString())).toBeInTheDocument();
30	    expect(screen.getByText(formatCurrency(summary.totalVolume))).toBeInTheDocument();
31	    expect(screen.getByText(summary.uniqueTraders.toLocaleString())).toBeInTheDocument();
32	    expect(
33	      screen.getByText(new Date(summary.lastUpdated).toLocaleString()),
34	    ).toBeInTheDocument();
35	  });
36	
37	  it("renders the Last Update caption text", () => {
38	    render(<AnalyticsSummaryCards summary={makeSummary()} />);
39	    expect(
40	      screen.getByText("Accepted activity freshness for the selected market."),
41	    ).toBeInTheDocument();
42	  });
43	
44	  it("handles zero values", () => {
45	    const summary = makeSummary({ totalTrades: 0, totalVolume: 0, uniqueTraders: 0 });
46	    render(<AnalyticsSummaryCards summary={summary} />);
47	
48	    // totalTrades and uniqueTraders both render "0"
49	    const zeros = screen.getAllByText((0).toLocaleString());
50	    expect(zeros).toHaveLength(2);
51	    expect(screen.getByText(formatCurrency(0))).toBeInTheDocument();
52	  });
53	
54	  it("handles large numbers", () => {
55	    const summary = makeSummary({
56	      totalTrades: 15000,
57	      totalVolume: 2500000,
58	      uniqueTraders: 8700,
59	    });
60	    render(<AnalyticsSummaryCards summary={summary} />);
61	
62	    expect(screen.getByText((15000).toLocaleString())).toBeInTheDocument();
63	    expect(screen.getByText(formatCurrency(2500000))).toBeInTheDocument();
64	    expect(screen.getByText((8700).toLocaleString())).toBeInTheDocument();
65	  });
66	});
